mapper.select:
select s.user_id, u.user_name, u.nick_name, s.team_level, s.calc_date, s.calc_depth, s.direct_user_count, s.direct_valid_user_count, s.team_user_count, s.team_valid_user_count, s.team_total_asset, s.team_total_invest, s.create_time, s.update_time from sys_team_stat_user s left join sys_user u on u.user_id = s.user_id
and s.user_id = #{userId} and u.user_name like concat('%', #{userName}, '%') and s.team_level = #{teamLevel} and s.calc_date >= #{params.beginTime} and s.calc_date <= #{params.endTime}
order by s.calc_date desc, s.team_total_invest desc, s.user_id asc

select
    e.event_id, e.stat_date, e.owner_user_id, e.member_user_id, e.relation_depth,
    e.event_type, e.event_amount, e.is_valid_user, e.biz_key, e.event_time, e.create_time
from sys_team_stat_event e

    and e.owner_user_id = #{ownerUserId}
    and e.member_user_id = #{memberUserId}
    and e.event_type = #{eventType}
    and e.stat_date = #{statDate}
    and e.event_time >= #{params.beginTime}
    and e.event_time <= #{params.endTime}

order by e.event_id desc
